import{_ as a,c as t,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Vista Diff: Revisar cambios desde múltiples perspectivas | Plannotator","description":"Aprende a alternar entre tipos de diff en la revisión de código de Plannotator. Selecciona vistas uncommitted, staged, last commit o branch desde el menú desplegable para revisar cambios de código desde múltiples perspectivas.","frontmatter":{"title":"Vista Diff: Revisar cambios desde múltiples perspectivas | Plannotator","sidebarTitle":"Alternar entre 5 vistas diff","subtitle":"Vista Diff: Revisar cambios desde múltiples perspectivas","description":"Aprende a alternar entre tipos de diff en la revisión de código de Plannotator. Selecciona vistas uncommitted, staged, last commit o branch desde el menú desplegable para revisar cambios de código desde múltiples perspectivas.","tags":["code-review","git","diff","tutorial"],"prerequisite":["code-review-basics"],"order":6},"headers":[],"relativePath":"es/backnotprop/plannotator/platforms/code-review-diff-types/index.md","filePath":"es/backnotprop/plannotator/platforms/code-review-diff-types/index.md"}'),r={name:"es/backnotprop/plannotator/platforms/code-review-diff-types/index.md"};function s(n,e,d,c,l,p){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="alternar-vista-diff" tabindex="-1">Alternar vista Diff <a class="header-anchor" href="#alternar-vista-diff" aria-label="Permalink to &quot;Alternar vista Diff&quot;">​</a></h1><h2 id="lo-que-aprenderas" tabindex="-1">Lo que aprenderás <a class="header-anchor" href="#lo-que-aprenderas" aria-label="Permalink to &quot;Lo que aprenderás&quot;">​</a></h2><p>Al revisar código, podrás:</p><ul><li>Usar el menú desplegable para alternar rápidamente entre 5 vistas diff</li><li>Entender el alcance de cambios de código que muestra cada vista</li><li>Seleccionar el tipo de diff apropiado según las necesidades de revisión</li><li>Evitar perder cambios importantes por seleccionar la vista incorrecta</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p><strong>Al revisar solo ves el área de trabajo, perdiendo archivos en staging</strong>:</p><p>Ejecutas el comando <code>/plannotator-review</code>, ves algunos cambios de código y añades algunos comentarios. Pero después del commit descubres que la revisión omitió esos archivos que ya habías agregado con <code>git add</code> al área de staging—estos archivos simplemente no aparecieron en el diff.</p><p><strong>Quieres conocer la diferencia total entre la rama actual y main</strong>:</p><p>Has estado desarrollando en una rama feature durante semanas, quieres ver todos los cambios realizados, pero la vista predeterminada de &quot;cambios no confirmados&quot; solo muestra las modificaciones de los últimos días.</p><p><strong>Quieres comparar diferencias entre dos commits específicos</strong>:</p><p>Quieres confirmar si una corrección de bug es correcta, necesitas comparar el código antes y después de la corrección, pero no sabes cómo hacer que Plannotator muestre el diff de commits históricos.</p><h2 id="cuando-usar-esto" tabindex="-1">Cuándo usar esto <a class="header-anchor" href="#cuando-usar-esto" aria-label="Permalink to &quot;Cuándo usar esto&quot;">​</a></h2><ul><li><strong>Revisión completa</strong>: Ver cambios tanto del área de trabajo como del área de staging simultáneamente</li><li><strong>Antes de fusionar ramas</strong>: Verificar todos los cambios de la rama actual respecto a main/master</li><li><strong>Revisión de rollback</strong>: Confirmar qué archivos cambió el último commit</li><li><strong>Colaboración en equipo</strong>: Verificar código que colegas han puesto en staging pero no han confirmado</li></ul><h2 id="concepto-principal" tabindex="-1">Concepto principal <a class="header-anchor" href="#concepto-principal" aria-label="Permalink to &quot;Concepto principal&quot;">​</a></h2><p>Los comandos git diff tienen muchas variantes, cada variante muestra un rango diferente de código. Plannotator concentra estas variantes en un menú desplegable, para que no necesites recordar comandos git complejos.</p><div class="info custom-block"><p class="custom-block-title">Referencia rápida de tipos Git Diff</p><table tabindex="0"><thead><tr><th>Tipo de diff</th><th>Alcance mostrado</th><th>Escenario de uso típico</th></tr></thead><tbody><tr><td>Uncommitted changes</td><td>Área de trabajo + staging</td><td>Revisar todas las modificaciones del desarrollo actual</td></tr><tr><td>Staged changes</td><td>Solo área de staging</td><td>Revisar contenido preparado para commit antes de confirmar</td></tr><tr><td>Unstaged changes</td><td>Solo área de trabajo</td><td>Revisar modificaciones que aún no han sido agregadas con <code>git add</code></td></tr><tr><td>Last commit</td><td>Último commit</td><td>Rollback o revisar el commit reciente</td></tr><tr><td>vs main</td><td>Rama actual vs rama predeterminada</td><td>Verificación completa antes de fusionar rama</td></tr></tbody></table></div><p>Las opciones del menú desplegable cambian dinámicamente según tu estado Git:</p><ul><li>Si no estás en la rama predeterminada, se mostrará la opción &quot;vs main&quot;</li><li>Si no hay archivos en staging, la vista Staged mostrará &quot;No staged changes&quot;</li></ul><h2 id="paso-a-paso" tabindex="-1">Paso a paso <a class="header-anchor" href="#paso-a-paso" aria-label="Permalink to &quot;Paso a paso&quot;">​</a></h2><h3 id="paso-1-iniciar-revision-de-codigo" tabindex="-1">Paso 1: Iniciar revisión de código <a class="header-anchor" href="#paso-1-iniciar-revision-de-codigo" aria-label="Permalink to &quot;Paso 1: Iniciar revisión de código&quot;">​</a></h3><p><strong>Por qué</strong></p><p>Necesitas abrir primero la interfaz de revisión de código de Plannotator.</p><p><strong>Operación</strong></p><p>Ejecuta en la terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>Deberías ver</strong></p><p>El navegador abre la página de revisión de código, en la parte superior del árbol de archivos del lado izquierdo hay un menú desplegable que muestra el tipo de diff actual (generalmente &quot;Uncommitted changes&quot;).</p><h3 id="paso-2-cambiar-a-vista-staged" tabindex="-1">Paso 2: Cambiar a vista Staged <a class="header-anchor" href="#paso-2-cambiar-a-vista-staged" aria-label="Permalink to &quot;Paso 2: Cambiar a vista Staged&quot;">​</a></h3><p><strong>Por qué</strong></p><p>Ver archivos que ya han sido agregados con <code>git add</code> pero aún no confirmados.</p><p><strong>Operación</strong></p><ol><li>Haz clic en el menú desplegable en la parte superior del árbol de archivos del lado izquierdo</li><li>Selecciona &quot;Staged changes&quot;</li></ol><p><strong>Deberías ver</strong></p><ul><li>Si hay archivos en staging, el árbol de archivos muestra estos archivos</li><li>Si no hay archivos en staging, el área principal muestra: &quot;No staged changes. Stage some files with git add.&quot;</li></ul><h3 id="paso-3-cambiar-a-vista-last-commit" tabindex="-1">Paso 3: Cambiar a vista Last Commit <a class="header-anchor" href="#paso-3-cambiar-a-vista-last-commit" aria-label="Permalink to &quot;Paso 3: Cambiar a vista Last Commit&quot;">​</a></h3><p><strong>Por qué</strong></p><p>Revisar el código recién confirmado para asegurar que no hay problemas.</p><p><strong>Operación</strong></p><ol><li>Abre nuevamente el menú desplegable</li><li>Selecciona &quot;Last commit&quot;</li></ol><p><strong>Deberías ver</strong></p><ul><li>Muestra todos los archivos modificados en el último commit</li><li>El contenido del diff es la diferencia <code>HEAD~1..HEAD</code></li></ul><h3 id="paso-4-cambiar-a-vista-vs-main-si-esta-disponible" tabindex="-1">Paso 4: Cambiar a vista vs main (si está disponible) <a class="header-anchor" href="#paso-4-cambiar-a-vista-vs-main-si-esta-disponible" aria-label="Permalink to &quot;Paso 4: Cambiar a vista vs main (si está disponible)&quot;">​</a></h3><p><strong>Por qué</strong></p><p>Ver todos los cambios de la rama actual respecto a la rama predeterminada.</p><p><strong>Operación</strong></p><ol><li>Verifica si hay una opción &quot;vs main&quot; o &quot;vs master&quot; en el menú desplegable</li><li>Si la hay, selecciónala</li></ol><p><strong>Deberías ver</strong></p><ul><li>El árbol de archivos muestra todos los archivos con diferencias entre la rama actual y la rama predeterminada</li><li>El contenido del diff son los cambios completos de <code>main..HEAD</code></li></ul><div class="tip custom-block"><p class="custom-block-title">Verificar rama actual</p><p>Si no ves la opción &quot;vs main&quot;, significa que estás en la rama predeterminada. Puedes usar el siguiente comando para ver la rama actual:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rev-parse</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --abbrev-ref</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD</span></span></code></pre></div><p>Intenta nuevamente después de cambiar a una rama feature:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div></div><h2 id="punto-de-verificacion-✅" tabindex="-1">Punto de verificación ✅ <a class="header-anchor" href="#punto-de-verificacion-✅" aria-label="Permalink to &quot;Punto de verificación ✅&quot;">​</a></h2><p>Confirma que has dominado:</p><ul><li>[ ] Puedes encontrar y abrir el menú desplegable de tipos de diff</li><li>[ ] Entiendes la diferencia entre &quot;Uncommitted&quot;, &quot;Staged&quot; y &quot;Last commit&quot;</li><li>[ ] Puedes identificar cuándo aparece la opción &quot;vs main&quot;</li><li>[ ] Sabes qué tipo de diff usar en cada escenario</li></ul><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><h3 id="error-1-al-revisar-solo-ves-uncommitted-perdiendo-archivos-staged" tabindex="-1">Error 1: Al revisar solo ves Uncommitted, perdiendo archivos Staged <a class="header-anchor" href="#error-1-al-revisar-solo-ves-uncommitted-perdiendo-archivos-staged" aria-label="Permalink to &quot;Error 1: Al revisar solo ves Uncommitted, perdiendo archivos Staged&quot;">​</a></h3><p><strong>Síntoma</strong></p><p>Después del commit descubres que la revisión omitió algunos archivos que ya estaban en staging.</p><p><strong>Causa</strong></p><p>La vista Uncommitted muestra todos los cambios del área de trabajo y staging (<code>git diff HEAD</code>), los archivos en staging también están incluidos.</p><p><strong>Solución</strong></p><p>Antes de revisar, cambia primero a la vista Staged para verificar, o usa la vista Uncommitted (incluye staging).</p><h3 id="error-2-no-comparar-con-main-antes-de-fusionar-rama" tabindex="-1">Error 2: No comparar con main antes de fusionar rama <a class="header-anchor" href="#error-2-no-comparar-con-main-antes-de-fusionar-rama" aria-label="Permalink to &quot;Error 2: No comparar con main antes de fusionar rama&quot;">​</a></h3><p><strong>Síntoma</strong></p><p>Después de fusionar a main descubres que se introdujeron modificaciones no relacionadas.</p><p><strong>Causa</strong></p><p>Solo viste los commits de los últimos días, no comparaste la diferencia de toda la rama respecto a main.</p><p><strong>Solución</strong></p><p>Antes de fusionar usa la vista &quot;vs main&quot; para verificar completamente.</p><h3 id="error-3-pensar-que-cambiar-de-vista-perdera-comentarios" tabindex="-1">Error 3: Pensar que cambiar de vista perderá comentarios <a class="header-anchor" href="#error-3-pensar-que-cambiar-de-vista-perdera-comentarios" aria-label="Permalink to &quot;Error 3: Pensar que cambiar de vista perderá comentarios&quot;">​</a></h3><p><strong>Síntoma</strong></p><p>No te atreves a cambiar el tipo de diff, temiendo que los comentarios añadidos previamente desaparezcan.</p><p><strong>Causa</strong></p><p>Malentendido del mecanismo de cambio.</p><p><strong>Situación real</strong></p><p>Al cambiar el tipo de diff, Plannotator conserva los comentarios anteriores—pueden seguir siendo aplicables, o puedes eliminar manualmente los comentarios no relacionados.</p><h2 id="resumen-de-la-leccion" tabindex="-1">Resumen de la lección <a class="header-anchor" href="#resumen-de-la-leccion" aria-label="Permalink to &quot;Resumen de la lección&quot;">​</a></h2><p>Los 5 tipos de diff que soporta Plannotator:</p><table tabindex="0"><thead><tr><th>Tipo</th><th>Comando Git</th><th>Escenario</th></tr></thead><tbody><tr><td>Uncommitted</td><td><code>git diff HEAD</code></td><td>Revisar todas las modificaciones del desarrollo actual</td></tr><tr><td>Staged</td><td><code>git diff --staged</code></td><td>Revisar área de staging antes de commit</td></tr><tr><td>Unstaged</td><td><code>git diff</code></td><td>Revisar modificaciones del área de trabajo</td></tr><tr><td>Last commit</td><td><code>git diff HEAD~1..HEAD</code></td><td>Rollback o revisar commit reciente</td></tr><tr><td>vs main</td><td><code>git diff main..HEAD</code></td><td>Verificación completa antes de fusionar rama</td></tr></tbody></table><p>Cambiar de vista no perderá comentarios, puedes ver el mismo lote o nuevos comentarios desde diferentes perspectivas.</p><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la próxima lección aprenderemos <strong><a href="./../../advanced/url-sharing/">Compartir URL</a></strong>.</p><p>Aprenderás:</p><ul><li>Cómo comprimir el contenido de revisión en una URL para compartir con colegas</li><li>Cómo el receptor abre el enlace de revisión compartido</li><li>Limitaciones y precauciones en modo compartido</li></ul></blockquote><hr><h2 id="apendice-referencia-del-codigo-fuente" tabindex="-1">Apéndice: Referencia del código fuente <a class="header-anchor" href="#apendice-referencia-del-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia del código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para ver la ubicación del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidad</th><th>Ruta del archivo</th><th>Líneas</th></tr></thead><tbody><tr><td>Definición de tipos Diff</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L10-L15" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>10-15</td></tr><tr><td>Obtención de contexto Git</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L79-L96" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>79-96</td></tr><tr><td>Ejecución de Git Diff</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L101-L147" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>101-147</td></tr><tr><td>Manejo de cambio de Diff</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L300-L331" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>300-331</td></tr><tr><td>Renderizado de opciones Diff en árbol de archivos</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/components/FileTree.tsx" target="_blank" rel="noreferrer"><code>packages/review-editor/components/FileTree.tsx</code></a></td><td>-</td></tr></tbody></table><p><strong>Tipos clave</strong>:</p><ul><li><code>DiffType</code>: <code>&#39;uncommitted&#39; | &#39;staged&#39; | &#39;unstaged&#39; | &#39;last-commit&#39; | &#39;branch&#39;</code></li></ul><p><strong>Funciones clave</strong>:</p><ul><li><code>getGitContext()</code>: Obtiene la rama actual, rama predeterminada y opciones de diff disponibles</li><li><code>runGitDiff(diffType, defaultBranch)</code>: Ejecuta el comando git correspondiente según el tipo de diff</li></ul><p><strong>API clave</strong>:</p><ul><li><code>POST /api/diff/switch</code>: Cambia el tipo de diff, devuelve nuevos datos de diff</li></ul></details>',83)])])}const g=a(r,[["render",s]]);export{u as __pageData,g as default};
